import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DFlFRONG.js";const m=JSON.parse('{"title":"TeamOne","titleTemplate":"Terms of Service","description":"","frontmatter":{"title":"TeamOne","titleTemplate":"Terms of Service"},"headers":[],"relativePath":"terms.md","filePath":"terms.md"}'),r={name:"terms.md"};function s(n,e,l,c,u,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="terms-of-service" tabindex="-1">Terms of Service <a class="header-anchor" href="#terms-of-service" aria-label="Permalink to &quot;Terms of Service&quot;">​</a></h1><p><em>Last updated: May 2026</em></p><p>These Terms of Service (&quot;Terms&quot;) govern your access to and use of <strong>TeamOne</strong>, the Google Sheets™ add-on for IBM Planning Analytics / TM1 provided by <strong>Succeedium</strong> (&quot;Succeedium&quot;, &quot;we&quot;, &quot;us&quot;, or &quot;our&quot;).</p><p>Please read these Terms carefully before installing, accessing, or using TeamOne.</p><p>By installing, accessing, or using TeamOne, you agree to be bound by these Terms. If you are using TeamOne on behalf of an organization, you represent that you have authority to bind that organization to these Terms. If you do not agree to these Terms, you may not install, access, or use TeamOne.</p><p>Please also review our <a href="https://succeedium.com/teamone/privacy" target="_blank" rel="noreferrer">Privacy Policy</a>, which explains how we handle information in connection with TeamOne.</p><h2 id="_1-scope-of-these-terms" tabindex="-1">1. Scope of These Terms <a class="header-anchor" href="#_1-scope-of-these-terms" aria-label="Permalink to &quot;1. Scope of These Terms&quot;">​</a></h2><p>These Terms apply to TeamOne, including the TeamOne Google Sheets add-on, related websites, documentation, support services, licensing systems, and any related services we provide.</p><p>These Terms do not apply to third-party products or services that are not owned or controlled by Succeedium, including Google Workspace, Google Sheets, IBM Planning Analytics, IBM Cloud, or other third-party platforms used by your organization.</p><p>If you or your organization has entered into a separate written agreement, order form, statement of work, data processing agreement, service level agreement, or other written agreement with Succeedium, that agreement may contain additional or different terms. If there is a conflict between these Terms and a separately signed or accepted agreement with Succeedium, the separately signed or accepted agreement will control to the extent of the conflict.</p><h2 id="_2-description-of-teamone" tabindex="-1">2. Description of TeamOne <a class="header-anchor" href="#_2-description-of-teamone" aria-label="Permalink to &quot;2. Description of TeamOne&quot;">​</a></h2><p>TeamOne allows authorized users to connect Google Sheets to IBM Planning Analytics / TM1 environments and work with IBM Planning Analytics metadata and data directly from Google Sheets.</p><p>TeamOne may include features for reading, displaying, refreshing, updating, writing back, organizing, validating, comparing, automating, or otherwise working with IBM Planning Analytics / TM1 data.</p><p>You are responsible for how TeamOne is configured and used within your organization, including the reports, formulas, writeback actions, data updates, tasks, processes, and other actions performed through TeamOne.</p><h2 id="_3-accounts-access-and-permissions" tabindex="-1">3. Accounts, Access, and Permissions <a class="header-anchor" href="#_3-accounts-access-and-permissions" aria-label="Permalink to &quot;3. Accounts, Access, and Permissions&quot;">​</a></h2><p>To use TeamOne, you may need:</p><ul><li>a Google account;</li><li>access to Google Sheets;</li><li>authorization to install or use the TeamOne add-on;</li><li>access to an IBM Planning Analytics / TM1 environment;</li><li>appropriate IBM Planning Analytics permissions;</li><li>a valid TeamOne license, subscription, trial, or other authorization.</li></ul><p>TeamOne may require Google account and Google Workspace permissions to operate inside Google Sheets. These permissions may include permission to display menus, prompts, screens, and sidebars, connect to external services, and view or manage spreadsheets where TeamOne has been installed or authorized.</p><p>You are responsible for ensuring that you have the required authority and permissions to use TeamOne with your Google Workspace and IBM Planning Analytics environments.</p><h2 id="_4-customer-responsibilities" tabindex="-1">4. Customer Responsibilities <a class="header-anchor" href="#_4-customer-responsibilities" aria-label="Permalink to &quot;4. Customer Responsibilities&quot;">​</a></h2><p>You and your organization are responsible for:</p><ul><li>managing Google Sheets sharing permissions;</li><li>managing IBM Planning Analytics users, roles, groups, permissions, and access controls;</li><li>ensuring only authorized users access TeamOne;</li><li>ensuring users are trained and authorized to retrieve, modify, or write back IBM Planning Analytics data;</li><li>reviewing formulas, reports, updates, writeback values, process executions, tasks, automations, and other actions before relying on them;</li><li>maintaining backups and recovery processes for business-critical systems and data;</li><li>ensuring your use of TeamOne complies with applicable laws, regulations, internal policies, and contractual obligations;</li><li>ensuring that any information submitted to TeamOne, support channels, or AI-assisted features is authorized by your organization.</li></ul><p>TeamOne may allow users to modify Google Sheets content, retrieve IBM Planning Analytics data, or submit updates to IBM Planning Analytics. You are responsible for the outcome of actions performed through TeamOne, including any changes to reports, spreadsheets, metadata, data, formatting, calculations, or IBM Planning Analytics content.</p><h2 id="_5-subscription-orders-and-payment" tabindex="-1">5. Subscription, Orders, and Payment <a class="header-anchor" href="#_5-subscription-orders-and-payment" aria-label="Permalink to &quot;5. Subscription, Orders, and Payment&quot;">​</a></h2><p>TeamOne is generally provided as an online, subscription-based product.</p><p>Subscription terms, fees, renewal terms, number of users, support level, payment terms, discounts, trials, evaluation periods, and other commercial terms may be set out in an applicable order form, invoice, quote, purchase order, statement of work, or other written agreement between you and Succeedium.</p><p>Unless otherwise stated in an applicable written agreement, all fees are non-refundable and payable in accordance with the applicable order or invoice.</p><p>If payment is overdue, or if your use of TeamOne exceeds the scope of your license or subscription, Succeedium may suspend or limit access to TeamOne after providing reasonable notice, unless immediate suspension is required for security, legal, or operational reasons.</p><h2 id="_6-changes-to-teamone" tabindex="-1">6. Changes to TeamOne <a class="header-anchor" href="#_6-changes-to-teamone" aria-label="Permalink to &quot;6. Changes to TeamOne&quot;">​</a></h2><p>TeamOne is an online product, and we may update, improve, modify, add, or discontinue features from time to time.</p><p>We make changes to TeamOne to improve performance, security, usability, reliability, compatibility, and compliance; to respond to customer feedback and product needs; and to address changes in Google Workspace, IBM Planning Analytics, IBM Cloud, APIs, security requirements, or applicable law.</p><p>We aim to improve TeamOne over time and avoid changes that materially reduce the value of existing paid subscriptions. Subject to our obligations under applicable orders or written agreements, we may modify or discontinue features where reasonably necessary for product development, security, reliability, compliance, third-party platform compatibility, or customer needs.</p><p>Where a change materially affects existing paid subscriptions, we will use commercially reasonable efforts to provide reasonable notice.</p><h2 id="_7-customer-data-and-processing" tabindex="-1">7. Customer Data and Processing <a class="header-anchor" href="#_7-customer-data-and-processing" aria-label="Permalink to &quot;7. Customer Data and Processing&quot;">​</a></h2><p>TeamOne processes information as needed to provide the functionality requested by the customer or authorized users.</p><p>Depending on how TeamOne is configured and used, TeamOne may process Google account information, Google Sheets information, IBM Planning Analytics connection information, IBM Planning Analytics metadata, IBM Planning Analytics data, support information, technical logs, diagnostics, and other information described in our <a href="https://succeedium.com/teamone/privacy" target="_blank" rel="noreferrer">Privacy Policy</a>.</p><p>TeamOne does not sell customer data.</p><p>Unless otherwise agreed or required for a specific feature, TeamOne is not designed to permanently store customer IBM Planning Analytics cube data. However, such data may be temporarily processed, transmitted, cached, logged, or included in support materials where necessary to provide the service, troubleshoot issues, maintain security, or comply with applicable legal or contractual obligations.</p><p>You are responsible for ensuring that your use of TeamOne, including any data submitted to or processed through TeamOne, is authorized by your organization and complies with applicable laws, internal policies, and agreements.</p><h2 id="_8-google-api-data-use" tabindex="-1">8. Google API Data Use <a class="header-anchor" href="#_8-google-api-data-use" aria-label="Permalink to &quot;8. Google API Data Use&quot;">​</a></h2><p>TeamOne’s use and transfer of information received from Google APIs complies with the <a href="https://developers.google.com/terms/api-services-user-data-policy" target="_blank" rel="noreferrer">Google API Services User Data Policy</a>, including the Limited Use requirements.</p><p>TeamOne uses information received from Google APIs only to provide and improve TeamOne’s user-facing features, maintain security, troubleshoot issues, prevent abuse, and comply with applicable legal or contractual obligations.</p><p>TeamOne does not use information received from Google APIs to train public, general-purpose, or non-personalized AI or machine learning models.</p><h2 id="_9-ai-assisted-features" tabindex="-1">9. AI-Assisted Features <a class="header-anchor" href="#_9-ai-assisted-features" aria-label="Permalink to &quot;9. AI-Assisted Features&quot;">​</a></h2><p>TeamOne may include optional AI-assisted features.</p><h3 id="_9-1-teamone-ai-help" tabindex="-1">9.1 TeamOne AI Help <a class="header-anchor" href="#_9-1-teamone-ai-help" aria-label="Permalink to &quot;9.1 TeamOne AI Help&quot;">​</a></h3><p>TeamOne AI Help is designed to assist users with TeamOne documentation, formulas, report-building, troubleshooting, examples, and general product usage.</p><p>TeamOne AI Help is not designed to access, analyze, or use customer IBM Planning Analytics / TM1 model metadata, cube data, or business data as context.</p><p>However, if a user voluntarily includes customer data, screenshots, formulas, report details, model information, metadata, or other confidential information in a prompt, support request, or AI interaction, that information may be processed to generate the requested response.</p><h3 id="_9-2-space-ai-assistant-and-teamone-space-integration" tabindex="-1">9.2 SPACE AI Assistant and TeamOne + SPACE Integration <a class="header-anchor" href="#_9-2-space-ai-assistant-and-teamone-space-integration" aria-label="Permalink to &quot;9.2 SPACE AI Assistant and TeamOne + SPACE Integration&quot;">​</a></h3><p>Customers who separately purchase, configure, and enable <strong>SPACE</strong> may have access to model-aware AI assistance through SPACE or through an integration between TeamOne and SPACE.</p><p>These features are separate from TeamOne AI Help. Unlike TeamOne AI Help, model-aware AI features may process customer-authorized IBM Planning Analytics / TM1 context, including model metadata, cube structures, dimensions, hierarchies, elements, subsets, views, attributes, rules, processes, chores, logs, report definitions, formulas, and other information made available by the customer or its authorized users.</p><p>Model-aware AI features are available only where SPACE has been purchased, configured, and enabled by the customer. Customers control whether these features are enabled and which authorized users or roles may access them, where such controls are supported.</p><p>Where supported, customers may configure SPACE AI Assistant to use a customer-controlled or private AI environment, such as a private cloud AI service, enterprise AI deployment, private GPT-style environment, or customer-managed AI provider. In such cases, prompts, model context, metadata, and generated outputs may be processed within the customer-selected AI environment, subject to the customer’s configuration, agreements, security controls, and provider terms.</p><h3 id="_9-3-ai-outputs" tabindex="-1">9.3 AI Outputs <a class="header-anchor" href="#_9-3-ai-outputs" aria-label="Permalink to &quot;9.3 AI Outputs&quot;">​</a></h3><p>AI-assisted features are provided for convenience and assistance only. AI-generated outputs may be inaccurate, incomplete, outdated, or inappropriate for your specific use case.</p><p>You are responsible for reviewing and validating any AI-generated suggestions, formulas, reports, explanations, code, configuration guidance, troubleshooting steps, or other outputs before relying on them.</p><p>AI-generated outputs should not be treated as professional, financial, legal, tax, accounting, security, or compliance advice. You remain responsible for decisions made using TeamOne, SPACE, IBM Planning Analytics, Google Sheets, or any related systems.</p><h3 id="_9-4-ai-data-use" tabindex="-1">9.4 AI Data Use <a class="header-anchor" href="#_9-4-ai-data-use" aria-label="Permalink to &quot;9.4 AI Data Use&quot;">​</a></h3><p>We do not sell customer data.</p><p>We do not use customer content submitted through TeamOne or SPACE AI-assisted features to train public or general-purpose AI models unless expressly agreed in writing.</p><p>AI-assisted features may use Succeedium-managed AI providers, third-party AI service providers, or customer-configured AI providers, including private or customer-controlled AI environments where supported. The data exposure and processing model may depend on the AI configuration selected by the customer.</p><p>Customers are responsible for reviewing and approving the AI configuration appropriate for their organization and ensuring users are authorized to submit information to AI-assisted features.</p><h2 id="_10-third-party-services" tabindex="-1">10. Third-Party Services <a class="header-anchor" href="#_10-third-party-services" aria-label="Permalink to &quot;10. Third-Party Services&quot;">​</a></h2><p>TeamOne interoperates with third-party platforms, including Google Workspace, Google Sheets, IBM Planning Analytics, IBM Cloud, cloud infrastructure providers, AI providers, and other services used or configured by you, your organization, or Succeedium.</p><p>Succeedium does not control and is not responsible for third-party products or services, including their availability, performance, security, privacy practices, API changes, service limitations, outages, errors, terms, or decisions.</p><p>Your use of third-party products and services is subject to the applicable third-party terms, policies, agreements, and configurations.</p><p>Succeedium is not responsible for loss, damage, delay, outage, error, or inability to use TeamOne caused by third-party products or services, customer systems, network issues, misconfiguration, lack of permissions, or changes to third-party APIs or platforms.</p><h2 id="_11-acceptable-use" tabindex="-1">11. Acceptable Use <a class="header-anchor" href="#_11-acceptable-use" aria-label="Permalink to &quot;11. Acceptable Use&quot;">​</a></h2><p>You may not use TeamOne to:</p><ul><li>violate any applicable law, regulation, or third-party right;</li><li>access, process, or disclose information without authorization;</li><li>bypass, disable, or interfere with security, licensing, access control, or usage limits;</li><li>reverse engineer, decompile, disassemble, copy, modify, or create derivative works of TeamOne except as permitted by law;</li><li>interfere with or disrupt TeamOne, Succeedium systems, Google systems, IBM systems, or other third-party systems;</li><li>introduce viruses, malware, harmful code, or malicious content;</li><li>perform unauthorized security testing, scanning, scraping, or automated access;</li><li>abuse APIs, overload systems, or circumvent rate limits;</li><li>use TeamOne to send spam, phishing, fraudulent, misleading, or unlawful content;</li><li>use TeamOne in a way that could damage, disable, overburden, or impair the service or related systems.</li></ul><p>Succeedium may investigate suspected violations of this section and may suspend or limit access where reasonably necessary to protect the service, customers, users, or third parties.</p><h2 id="_12-suspension-and-termination" tabindex="-1">12. Suspension and Termination <a class="header-anchor" href="#_12-suspension-and-termination" aria-label="Permalink to &quot;12. Suspension and Termination&quot;">​</a></h2><p>Succeedium may suspend or terminate access to TeamOne if:</p><ul><li>you violate these Terms or another applicable agreement;</li><li>payment is overdue;</li><li>your subscription expires or is not renewed;</li><li>your use exceeds the scope of your license or subscription;</li><li>your use creates a security, legal, operational, or reputational risk;</li><li>suspension is required by law, court order, third-party platform requirement, or governmental authority;</li><li>continued access could harm Succeedium, customers, users, third parties, or related systems.</li></ul><p>Where reasonable under the circumstances, Succeedium will provide notice before suspension or termination. However, Succeedium may suspend access immediately where necessary to address security, legal, operational, or abuse-related risks.</p><p>Upon termination or expiration of your subscription, your right to access and use TeamOne will end, unless otherwise agreed in writing.</p><h2 id="_13-intellectual-property" tabindex="-1">13. Intellectual Property <a class="header-anchor" href="#_13-intellectual-property" aria-label="Permalink to &quot;13. Intellectual Property&quot;">​</a></h2><p>TeamOne, including its software, code, design, user interface, documentation, workflows, features, trademarks, logos, content, and related materials, is owned by Succeedium or its licensors and is protected by applicable intellectual property laws.</p><p>Subject to these Terms and any applicable order or written agreement, Succeedium grants you a limited, non-exclusive, non-transferable, non-sublicensable, revocable right to use TeamOne during the applicable subscription, trial, or authorized use period.</p><p>You do not acquire any ownership rights in TeamOne.</p><p>You retain ownership of your data, reports, spreadsheets, IBM Planning Analytics content, prompts, inputs, and other customer-provided materials, subject to the rights and permissions necessary for Succeedium to provide, secure, support, and improve TeamOne.</p><h2 id="_14-feedback" tabindex="-1">14. Feedback <a class="header-anchor" href="#_14-feedback" aria-label="Permalink to &quot;14. Feedback&quot;">​</a></h2><p>If you provide suggestions, ideas, enhancement requests, recommendations, bug reports, or other feedback about TeamOne, you grant Succeedium a worldwide, perpetual, irrevocable, royalty-free right to use, modify, and incorporate that feedback into TeamOne or other Succeedium products and services without obligation to you.</p><h2 id="_15-confidentiality" tabindex="-1">15. Confidentiality <a class="header-anchor" href="#_15-confidentiality" aria-label="Permalink to &quot;15. Confidentiality&quot;">​</a></h2><p>In connection with TeamOne, either party may receive confidential or proprietary information from the other party.</p><p>Each party agrees to use the other party’s confidential information only for purposes related to TeamOne and to protect it using reasonable care. Confidential information does not include information that is publicly available, already known without confidentiality obligations, independently developed, or lawfully received from a third party without confidentiality obligations.</p><p>Succeedium may process customer information as described in these Terms, the Privacy Policy, applicable agreements, and customer instructions.</p><h2 id="_16-support" tabindex="-1">16. Support <a class="header-anchor" href="#_16-support" aria-label="Permalink to &quot;16. Support&quot;">​</a></h2><p>Succeedium may provide support for TeamOne through email, help desk systems, documentation, meetings, or other support channels.</p><p>Support availability, response times, service levels, training, implementation assistance, and dedicated support commitments may depend on your subscription plan, order form, service level agreement, or other written agreement.</p><p>Unless otherwise agreed in writing, support is provided on a commercially reasonable basis and does not guarantee resolution of every issue.</p><h2 id="_17-beta-trial-evaluation-and-preview-features" tabindex="-1">17. Beta, Trial, Evaluation, and Preview Features <a class="header-anchor" href="#_17-beta-trial-evaluation-and-preview-features" aria-label="Permalink to &quot;17. Beta, Trial, Evaluation, and Preview Features&quot;">​</a></h2><p>Succeedium may offer beta, trial, evaluation, preview, experimental, or early-access features.</p><p>Such features may be incomplete, unsupported, changed, limited, suspended, or discontinued at any time. They may contain errors or produce unexpected results.</p><p>Unless otherwise agreed in writing, beta, trial, evaluation, preview, experimental, or early-access features are provided &quot;as is&quot; and without warranties, service level commitments, or support obligations.</p><h2 id="_18-disclaimers" tabindex="-1">18. Disclaimers <a class="header-anchor" href="#_18-disclaimers" aria-label="Permalink to &quot;18. Disclaimers&quot;">​</a></h2><p>Succeedium uses commercially reasonable efforts to operate, maintain, and secure TeamOne. However, except as expressly stated in a written agreement with Succeedium, TeamOne is provided on an &quot;as is&quot; and &quot;as available&quot; basis.</p><p>To the maximum extent permitted by law, Succeedium disclaims all warranties, representations, and conditions, whether express, implied, statutory, or otherwise, including warranties of merchantability, fitness for a particular purpose, title, non-infringement, accuracy, availability, reliability, uninterrupted access, error-free operation, and compatibility with third-party products or services.</p><p>Succeedium does not warrant that TeamOne will be uninterrupted, error-free, free of harmful components, or that all defects will be corrected.</p><p>Succeedium does not control Google Workspace, Google Sheets, IBM Planning Analytics, IBM Cloud, customer systems, customer networks, customer configurations, or third-party services, and is not responsible for issues caused by them.</p><p>You are responsible for verifying reports, formulas, data, writeback values, AI-generated outputs, and other results before relying on them.</p><h2 id="_19-limitation-of-liability" tabindex="-1">19. Limitation of Liability <a class="header-anchor" href="#_19-limitation-of-liability" aria-label="Permalink to &quot;19. Limitation of Liability&quot;">​</a></h2><p>To the maximum extent permitted by law, Succeedium will not be liable for any indirect, incidental, special, consequential, exemplary, punitive, or similar damages, or for any loss of profits, revenue, business, goodwill, data, use, or business interruption, whether based in contract, tort, negligence, strict liability, or any other legal theory, even if Succeedium has been advised of the possibility of such damages.</p><p>To the maximum extent permitted by law, Succeedium’s total aggregate liability arising out of or relating to TeamOne, these Terms, or any related services will not exceed the amounts paid by you or your organization to Succeedium for TeamOne during the twelve months before the event giving rise to the claim.</p><p>The limitations in this section apply to the maximum extent permitted by law and do not limit liability that cannot legally be limited.</p><p>Certain jurisdictions do not allow certain exclusions or limitations of liability. In such jurisdictions, Succeedium’s liability will be limited to the maximum extent permitted by law.</p><h2 id="_20-indemnity" tabindex="-1">20. Indemnity <a class="header-anchor" href="#_20-indemnity" aria-label="Permalink to &quot;20. Indemnity&quot;">​</a></h2><p>You agree to defend, indemnify, and hold harmless Succeedium and its affiliates, officers, directors, employees, contractors, agents, suppliers, and licensors from and against any claims, damages, losses, liabilities, costs, and expenses, including reasonable legal fees, arising out of or relating to:</p><ul><li>your use of TeamOne;</li><li>your violation of these Terms;</li><li>your violation of applicable law or third-party rights;</li><li>your data, systems, configurations, reports, formulas, prompts, inputs, or outputs;</li><li>unauthorized access, use, disclosure, or processing caused by your users, systems, credentials, permissions, configurations, or instructions.</li></ul><h2 id="_21-changes-to-these-terms" tabindex="-1">21. Changes to These Terms <a class="header-anchor" href="#_21-changes-to-these-terms" aria-label="Permalink to &quot;21. Changes to These Terms&quot;">​</a></h2><p>We may update these Terms from time to time.</p><p>When we make changes, we will update the “Last updated” date at the top of this page.</p><p>If we make material changes, we will provide notice by reasonable means, which may include posting a notice on our website, providing notice through the Service, sending notice to account administrators or billing contacts, or including the change in release notes or other customer communications.</p><p>Unless otherwise stated, updated Terms become effective when posted. If a change materially affects existing paid subscriptions, we will use commercially reasonable efforts to provide advance notice before the change takes effect.</p><p>Your continued use of TeamOne after the effective date of updated Terms constitutes acceptance of the updated Terms.</p><h2 id="_22-governing-law" tabindex="-1">22. Governing Law <a class="header-anchor" href="#_22-governing-law" aria-label="Permalink to &quot;22. Governing Law&quot;">​</a></h2><p>These Terms are governed by the laws of Canada and the applicable laws of the province where Succeedium is based, without regard to conflict of law principles.</p><p>The courts located in that province will have exclusive jurisdiction over disputes arising out of or relating to these Terms or TeamOne, unless otherwise required by applicable law or agreed in writing.</p><h2 id="_23-contact-us" tabindex="-1">23. Contact Us <a class="header-anchor" href="#_23-contact-us" aria-label="Permalink to &quot;23. Contact Us&quot;">​</a></h2><p>If you have any questions about these Terms, please contact us at:</p><p><a href="https://succeedium.com" target="_blank" rel="noreferrer">Succeedium</a><br> Email: <a href="mailto:info@succeedium.com" target="_blank" rel="noreferrer">info@succeedium.com</a></p><hr><p><em><a href="https://www.google.com/sheets/about/" target="_blank" rel="noreferrer">Google Sheets</a></em> is a trademark of Google LLC.<br><em>IBM</em>, <em>Planning Analytics</em>, and <em>TM1</em> are trademarks of International Business Machines Corporation.</p>',124)])])}const h=a(r,[["render",s]]);export{m as __pageData,h as default};
